 13	// Forward declarations
 14	struct ASTResult;
 15	struct ExtractionConfig;
 16	class UnifiedASTBackend;
 17	
 18	// Type for the parsing function - takes adapter and parsing parameters, returns ASTResult
 19	using ParsingFunction =
 20	    std::function<ASTResult(const void *, const string &, const string &, const string &, int32_t, const string &)>;
 21	
 22	// Base class for language-specific adapters
 23	class LanguageAdapter {
 24	public:
 25		virtual ~LanguageAdapter();
 26	
 27		// Language identification
 28		virtual string GetLanguageName() const = 0;
 29		virtual vector<string> GetAliases() const = 0;
 30	
 31		// Get the optimized parsing function for this language (single virtual call)
 32		virtual ParsingFunction GetParsingFunction() const = 0;
 33	
 34		// Core functionality - type normalization and content extraction
 35		virtual string GetNormalizedType(const string &node_type) const = 0;
 36		virtual string ExtractNodeName(TSNode node, const string &content) const = 0;
 37		virtual string ExtractNodeValue(TSNode node, const string &content) const = 0;
 38	
 39		// Basic node properties
 40		virtual bool IsPublicNode(TSNode node, const string &content) const = 0;
 41	
 42		// Non-virtual hot loop optimizations - these are identical across all adapters
 43		uint8_t GetNodeFlags(const string &node_type) const {
 44			const NodeConfig *config = GetNodeConfig(node_type);
 45			return config ? config->flags : 0;
 46		}
 47	
 48		// Get node configuration - non-virtual base implementation
 49		const NodeConfig *GetNodeConfig(const string &node_type) const {
 50			const auto &configs = GetNodeConfigs(); // Single virtual call
 51			auto it = configs.find(node_type);
 52			return (it != configs.end()) ? &it->second : nullptr;
 53		}
 54	
 55		// Get parser (lazy initialization) - made public for registry access
 56		TSParser *GetParser() const {
 57			if (!parser_wrapper_) {
 58				InitializeParser();
 59			}
 60			return parser_wrapper_->get();
 61		}
 62	
 63		// Parse content directly and return owned tree
 64		// Creates a fresh parser instance for each call to avoid shared state issues
 65		TSTreePtr ParseContent(const string &content) const {
 66			auto fresh_parser = CreateFreshParser();
 67			return fresh_parser->ParseString(content);
 68		}
 69	
 70		// Pure virtual method to get the static node configs map - each adapter implements this
 71		// Made public for template function access (performance optimization)
 72		virtual const unordered_map<string, NodeConfig> &GetNodeConfigs() const = 0;
 73	
 74	protected:
 75		// Owned parser instance - created once per adapter
 76		mutable unique_ptr<TSParserWrapper> parser_wrapper_;
 77	
 78		// Initialize parser with language-specific settings
 79		virtual void InitializeParser() const = 0;
 80	
 81		// Create a fresh parser instance (for thread safety)
 82		virtual unique_ptr<TSParserWrapper> CreateFreshParser() const = 0;
 83	
 84		// Helper methods for content extraction
 85		string ExtractNodeText(TSNode node, const string &content) const;
 86		string FindChildByType(TSNode node, const string &content, const string &child_type) const;
 87		string ExtractByStrategy(TSNode node, const string &content, ExtractionStrategy strategy) const;
 88	
 89		// Qualified identifier extraction helpers
 90		string ExtractQualifiedIdentifierName(TSNode node, const string &content) const;
 91		TSNode FindChildByTypeNode(TSNode node, const string &child_type) const;
 92		string ExtractNameFromQualifiedNode(TSNode qualified_node, const string &content) const;
 93		string ExtractNameFromDeclarator(TSNode node, const string &content) const;
 94		string ExtractFunctionNameFromText(TSNode node, const string &content) const;
 95	
 96		// FIND_IDENTIFIER helpers for searching through wrapper nodes
 97		string FindIdentifierInChildren(TSNode node, const string &content) const;
 98		string FindIdentifierInWrappers(TSNode node, const string &content, int depth) const;
 99	};
