 51	string PythonAdapter::GetNormalizedType(const string &node_type) const {
 52		const NodeConfig *config = GetNodeConfig(node_type);
 53		if (config) {
 54			return SemanticTypes::GetSemanticTypeName(config->semantic_type);
 55		}
 56		return node_type; // Fallback to raw type
 57	}
 58	
 59	string PythonAdapter::ExtractNodeName(TSNode node, const string &content) const {
 60		const char *node_type_str = ts_node_type(node);
 61		const NodeConfig *config = GetNodeConfig(node_type_str);
 62	
 63		if (config) {
 64			// Import statements: module name is in dotted_name child, not identifier
 65			if (strcmp(node_type_str, "import_statement") == 0 || strcmp(node_type_str, "import_from_statement") == 0) {
 66				string name = FindChildByType(node, content, "dotted_name");
 67				if (name.empty()) {
 68					// Relative imports (e.g., "from . import name") have no dotted_name
 69					name = FindChildByType(node, content, "identifier");
 70				}
 71				return name;
 72			}
 73			return ExtractByStrategy(node, content, config->name_strategy);
 74		}
 75	
 76		// Fallback: try to find identifier child for common declaration types
 77		string node_type = string(node_type_str);
 78		if (node_type.find("definition") != string::npos || node_type.find("declaration") != string::npos) {
 79			return FindChildByType(node, content, "identifier");
 80		}
 81	
 82		return "";
 83	}
