 86		const char *node_type_str = ts_node_type(node);
 87		const NodeConfig *config = GetNodeConfig(node_type_str);
 88	
 89		if (config) {
 90			// Note: value_strategy is now repurposed as native_strategy for pattern-based extraction
 91			// For backward compatibility, we'll return empty string since most nodes don't need legacy value extraction
 92			return "";
 93		}
 94	
 95		return "";
 96	}
