110		return [](const void *adapter, const string &content, const string &language, const string &file_path,
111		          int32_t peek_size, const string &peek_mode) -> ASTResult {
112			auto python_adapter = static_cast<const PythonAdapter *>(adapter);
113			return UnifiedASTBackend::ParseToASTResultTemplated(python_adapter, content, language, file_path, peek_size,
